// // This D-flip-flop will set Q to 1 on the rising edge of CLK when RST is low.
module d_flip_flop (
    input wire D,
    input wire CLK,
    input wire RST,
    output reg Q
);
    always @(posedge CLK or posedge RST) begin
        if (RST) begin
            Q <= 0;
        end else begin
            Q <= D;
        end
    end
endmodule
